#[derive(Debug)]
pub struct Machine;

impl ars_core::Machine for Machine {
    type State = State;
    type Event = Event;
    type Context = Context;
    type Props = Props;
    type Messages = Messages;
    type Effect = Effect;
    type Api<'a> = Api<'a>;

    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (State, Context) {
        (State::Idle, Context { ... })
    }

    fn transition(
        state: &Self::State,
        event: &Self::Event,
        _ctx: &Self::Context,
        props: &Self::Props,
    ) -> Option<TransitionPlan<Self>> {
        match (state, event) {
            (_, Event::Copy) if props.disabled => None,
            (State::Idle, Event::Copy) => Some(copying_plan()),
            (State::Copied | State::Error, Event::Copy) => {
                Some(copying_plan().cancel_effect(Effect::FeedbackTimer))
            }
            // ... more match arms
            _ => None,
        }
    }

    fn on_props_changed(old: &Props, new: &Props) -> Vec<Event> {
        assert_eq!(old.id, new.id, "clipboard::Props.id must remain stable after init");
        let mut events = Vec::new();
        if old.value != new.value {
            events.push(Event::SetValue(new.value.clone()));
        }
        if old.feedback_duration_ms != new.feedback_duration_ms || old.disabled != new.disabled {
            events.push(Event::SetProps);
        }
        events
    }

    fn connect<'a>(
        state: &'a Self::State,
        ctx: &'a Self::Context,
        props: &'a Self::Props,
        send: &'a dyn Fn(Self::Event),
    ) -> Self::Api<'a> {
        Api { state, ctx, props, send }
    }
}
```

