17	The following types define the signature data model:
18	
19	```rust
20	/// A single point in a signature stroke.
21	#[derive(Clone, Copy, Debug, PartialEq)]
22	pub struct SignaturePoint {
23	    /// The x coordinate of the point.
24	    pub x: f64,
25	    /// The y coordinate of the point.
26	    pub y: f64,
27	    /// Pressure from 0.0 to 1.0 (for pressure-sensitive input).
28	    pub pressure: f64,
29	    /// Timestamp in milliseconds.
30	    pub timestamp: f64,
31	}
32	
33	/// A continuous stroke (pen-down to pen-up).
34	#[derive(Clone, Debug, PartialEq)]
35	pub struct SignatureStroke {
36	    /// The points in the stroke.
37	    pub points: Vec<SignaturePoint>,
38	}
39	
40	/// The complete signature data.
41	#[derive(Clone, Debug, PartialEq, Default)]
42	pub struct SignatureData {
43	    /// The strokes in the signature.
44	    pub strokes: Vec<SignatureStroke>,
45	}
46	
47	impl SignatureData {
48	    /// Check if the signature data is empty.
49	    pub fn is_empty(&self) -> bool {
50	        self.strokes.is_empty()
51	    }
52	
53	    /// Convert to SVG path data string.
54	    pub fn to_svg_path(&self) -> String {
55	        let mut path = String::new();
56	        for stroke in &self.strokes {
57	            if stroke.points.is_empty() { continue; }
58	            path.push_str(format!("M{:.1},{:.1}", stroke.points[0].x, stroke.points[0].y));
59	            for point in &stroke.points[1..] {
60	                path.push_str(format!(" L{:.1},{:.1}", point.x, point.y));
61	            }
62	        }
63	        path
64	    }
65	
66	    /// Total number of points across all strokes.
67	    pub fn point_count(&self) -> usize {
68	        self.strokes.iter().map(|s| s.points.len()).sum()
69	    }
70	}
