75	    /// PNG format.
76	    Png,
77	    /// SVG format.
78	    Svg,
79	    /// JPEG format.
80	    Jpeg,
81	    /// Base64-encoded PNG format.
82	    Base64Png,
83	    /// Raw point data.
84	    Points,
85	}
