89	pub enum SignatureExport {
90	    /// PNG image bytes.
91	    Png(Vec<u8>),
92	    /// SVG markup string.
93	    Svg(String),
94	    /// JPEG image bytes.
95	    Jpeg(Vec<u8>),
96	    /// Base64-encoded PNG string (suitable for `data:` URIs).
97	    Base64(String),
98	    /// Raw point data for vector reconstruction.
99	    /// Each inner `Vec` is one continuous stroke.
100	    Points(Vec<Vec<SignaturePoint>>),
101	}
