103	impl SignatureData {
104	    /// Export the signature in the requested format.
105	    ///
106	    /// For `Png`, `Jpeg`, and `Base64Png`, the adapter renders strokes onto
107	    /// an off-screen canvas and encodes the result. For `Svg`, the core
108	    /// library generates the markup from stroke data. For `Points`, the raw
109	    /// `SignaturePoint` vectors are returned directly, enabling server-side
110	    /// vector reconstruction regardless of display resolution.
111	    pub fn export(&self, format: SignatureFormat) -> SignatureExport {
112	        match format {
113	            SignatureFormat::Svg => SignatureExport::Svg(self.to_svg_path()),
114	            SignatureFormat::Points => {
