256	### 1.5 Full Machine Implementation
257	
258	```rust
259	/// The machine for the `SignaturePad` component.
260	pub struct Machine;
261	
262	impl ars_core::Machine for Machine {
263	    type State = State;
264	    type Event = Event;
265	    type Context = Context;
266	    type Props = Props;
267	    type Messages = Messages;
268	    type Api<'a> = Api<'a>;
269	
270	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (Self::State, Self::Context) {
271	        let data = match &props.data {
272	            Some(d) => Bindable::controlled(d.clone()),
273	            None => Bindable::uncontrolled(props.default_data.clone()),
274	        };
275	
276	        let state = if data.get().is_empty() {
277	            State::Idle
278	        } else {
279	            State::Completed
280	        };
281	
282	        let ids = ComponentIds::from_id(&props.id);
283	        let locale = env.locale.clone();
284	        let messages = messages.clone();
285	
286	        (state, Context {
287	            data,
288	            current_stroke: None,
289	            disabled: props.disabled,
290	            readonly: props.readonly,
291	            pen_color: props.pen_color.clone(),
292	            pen_width: props.pen_width,
293	            min_distance: props.min_distance,
294	            focused: false,
295	            locale,
296	            messages,
297	            ids,
298	        })
299	    }
300	
301	    fn transition(
302	        state: &Self::State,
303	        event: &Self::Event,
304	        ctx: &Self::Context,
305	        _props: &Self::Props,
306	    ) -> Option<TransitionPlan<Self>> {
307	        // Focus/Blur always pass through regardless of disabled/readonly.
308	        match event {
309	            Event::Focus => {
310	                return Some(TransitionPlan::context_only(|ctx| ctx.focused = true));
311	            }
312	            Event::Blur => {
313	                return Some(TransitionPlan::context_only(|ctx| ctx.focused = false));
314	            }
315	            _ => {}
316	        }
317	
318	        if ctx.disabled || ctx.readonly {
319	            return None;
320	        }
321	
322	        match (state, event) {
323	            // Start drawing
324	            (State::Idle | State::Completed, Event::DrawStart { x, y, pressure }) => {
325	                let x = *x;
326	                let y = *y;
327	                let pressure = *pressure;
328	                Some(TransitionPlan::to(State::Drawing).apply(move |ctx| {
329	                    ctx.current_stroke = Some(SignatureStroke {
330	                        points: vec![SignaturePoint {
331	                            x, y, pressure, timestamp: 0.0,
332	                        }],
333	                    });
334	                }).with_named_effect("drawing-listeners", |_ctx, _props, send| {
335	                    let platform = use_platform_effects();
336	                    let send_move = send.clone();
337	                    let send_up = send.clone();
338	                    platform.track_pointer_drag(
339	                        Box::new(move |x, y| { send_move.call_if_alive(Event::DrawMove { x, y, pressure: 0.5 }); }),
340	                        Box::new(move || { send_up.call_if_alive(Event::DrawEnd); }),
341	                    )
342	                }))
343	            }
344	
345	            // Continue drawing
346	            (State::Drawing, Event::DrawMove { x, y, pressure }) => {
347	                let x = *x;
348	                let y = *y;
349	                let pressure = *pressure;
350	                Some(TransitionPlan::context_only(move |ctx| {
351	                    if let Some(ref mut stroke) = ctx.current_stroke {
352	                        if let Some(last) = stroke.points.last() {
353	                            let dx = x - last.x;
354	                            let dy = y - last.y;
355	                            let dist = (dx * dx + dy * dy).sqrt();
356	                            if dist >= ctx.min_distance {
357	                                stroke.points.push(SignaturePoint {
358	                                    x, y, pressure, timestamp: 0.0,
359	                                });
360	                            }
361	                        }
362	                    }
363	                }))
364	            }
365	
366	            // End drawing
367	            (State::Drawing, Event::DrawEnd) => {
368	                Some(TransitionPlan::to(State::Completed).apply(|ctx| {
369	                    if let Some(stroke) = ctx.current_stroke.take() {
370	                        if stroke.points.len() >= 2 {
371	                            let mut data = ctx.data.get().clone();
372	                            data.strokes.push(stroke);
373	                            ctx.data.set(data);
374	                        }
375	                    }
376	                }).with_named_effect("announce-provided", |ctx, _props, _send| {
377	                    let platform = use_platform_effects();
378	                    platform.announce(&(ctx.messages.signature_provided)(&ctx.locale));
379	                    no_cleanup()
380	                }))
381	            }
382	
383	            // Undo last stroke
384	            (State::Completed, Event::Undo) => {
385	                Some(TransitionPlan::context_only(|ctx| {
386	                    let mut data = ctx.data.get().clone();
387	                    data.strokes.pop();
388	                    ctx.data.set(data);
389	                }))
390	            }
391	
392	            // Clear all strokes
393	            (_, Event::Clear) => {
394	                Some(TransitionPlan::to(State::Idle).apply(|ctx| {
395	                    ctx.data.set(SignatureData::default());
396	                    ctx.current_stroke = None;
397	                }).with_named_effect("announce-cleared", |ctx, _props, _send| {
398	                    let platform = use_platform_effects();
399	                    platform.announce(&(ctx.messages.signature_cleared)(&ctx.locale));
400	                    no_cleanup()
401	                }))
402	            }
403	
404	            _ => None,
405	        }
406	    }
407	
408	    fn connect(
409	        state: &'a Self::State,
410	        ctx: &'a Self::Context,
411	        props: &'a Self::Props,
412	        send: &'a dyn Fn(Self::Event),
413	    ) -> Self::Api<'a> {
414	        Api { state, ctx, props, send }
415	    }
416	}
417	```
