    #[test]
    fn hidden_input_carries_name_and_svg_path() {
        let api = filled_api(State::Completed);
        let attrs = api.hidden_input_attrs();
        assert_eq!(attrs.get(&HtmlAttr::Name), Some("signature"));
        assert_eq!(
            attrs.get(&HtmlAttr::Value).map(str::to_string),
