    #[test]
    fn snapshot_root_disabled() {
        let api = api_for(State::Idle, SignatureData::default(), true, false, false);
        assert_snapshot!(snapshot_attrs(&api.root_attrs()));
    }

    #[test]
    fn snapshot_root_readonly() {
