fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (State, Context) {
    let data = match &props.data {
        Some(data) => Bindable::controlled(data.clone()),
        None => Bindable::uncontrolled(props.default_data.clone()),
    };

    let state = if data.get().is_empty() {
        State::Idle
    } else {
        State::Completed
    };

    (
        state,
        Context {
            data,
            current_stroke: None,
            disabled: props.disabled,
            readonly: props.readonly,
            pen_color: props.pen_color.clone(),
            pen_width: props.pen_width,
            min_distance: props.min_distance,
            focused: false,
            locale: env.locale.clone(),
            messages: messages.clone(),
            ids: ComponentIds::from_id(&props.id),
        },
    )
}

fn on_props_changed(old: &Props, new: &Props) -> Vec<Event> {
    assert_eq!(
        old.id, new.id,
        "signature_pad::Props.id must remain stable after init"
    );

    Vec::new()
}

fn transition(
    state: &Self::State,
    event: &Self::Event,
    ctx: &Self::Context,
    _props: &Self::Props,
) -> Option<TransitionPlan<Self>> {
    // Focus/Blur always pass through regardless of disabled/readonly.
    match event {
        Event::Focus => {
            return Some(TransitionPlan::context_only(|ctx: &mut Context| {
                ctx.focused = true;
            }));
        }
        Event::Blur => {
            return Some(TransitionPlan::context_only(|ctx: &mut Context| {
                ctx.focused = false;
            }));
        }

