    let new_data = props.data.clone();
    // Reconcile the displayed state with the new controlled data,
    // but never reorder an in-flight stroke. Switching to
    // uncontrolled mode (`None`) keeps the existing local value.
    let plan = match (&new_data, matches!(state, State::Drawing)) {
        (_, true) | (None, _) => TransitionPlan::new(),
        (Some(data), false) => TransitionPlan::to(if data.is_empty() {
            State::Idle
        } else {
            State::Completed
        }),
    };
    return Some(plan.apply(move |ctx: &mut Context| {
        if let Some(data) = new_data {
            ctx.data.set(data.clone());
            ctx.data.sync_controlled(Some(data));
        } else {
            ctx.data.sync_controlled(None);
        }
    }));
}

