    /// Export the signature in the requested format.
    ///
    /// For [`SignatureFormat::Svg`] the core generates the markup from stroke
    /// data; for [`SignatureFormat::Points`] the raw [`SignaturePoint`] vectors
    /// are returned directly, enabling server-side vector reconstruction
    /// regardless of display resolution.
    ///
    /// [`SignatureFormat::Png`], [`SignatureFormat::Jpeg`], and
    /// [`SignatureFormat::Base64Png`] require an off-screen canvas and are
    /// rendered by the adapter layer; calling `export` with those formats on the
    /// agnostic core panics. Adapters render strokes onto a canvas and encode the
    /// result rather than calling this method for raster output.
    #[must_use]
    pub fn export(&self, format: SignatureFormat) -> SignatureExport {
        match format {
            SignatureFormat::Svg => SignatureExport::Svg(self.to_svg_path()),

            SignatureFormat::Points => SignatureExport::Points(
                self.strokes
                    .iter()
                    .map(|stroke| stroke.points.clone())
                    .collect(),
            ),

            // Png, Jpeg, Base64Png require adapter-side canvas rendering.
            SignatureFormat::Png | SignatureFormat::Jpeg | SignatureFormat::Base64Png => {
                unimplemented!("Raster export is handled by the adapter layer")
            }
        }
    }
}

