1	//! Browser-backed [`ars_core::SignatureRasterizer`] implementation.
2	//!
3	//! Renders signature strokes onto an offscreen `<canvas>` and encodes the
4	//! result with `canvas.toDataURL`, decoding the data URL back to raw image
5	//! bytes. Stroke width is modulated by per-point pressure so firmer presses
6	//! draw thicker segments.
7	
8	use ars_core::{RasterError, RasterImage, RasterPoint, RasterSpec, SignatureRasterizer};
9	#[cfg(all(feature = "web", target_arch = "wasm32"))]
10	use {
11	    ars_core::RasterFormat,
12	    wasm_bindgen::{JsCast, JsValue},
13	    web_sys::{CanvasRenderingContext2d, HtmlCanvasElement, Window},
14	};
15	
16	/// Production [`SignatureRasterizer`] for browser builds.
17	///
18	/// Rasterizes strokes via an offscreen `<canvas>` 2D context and `toDataURL`.
19	/// On non-wasm targets (e.g. SSR type-checking) every call returns
20	/// [`RasterError::Unsupported`].
21	#[derive(Debug, Default, Clone, Copy)]
22	pub struct WebSignatureRasterizer;
23	
24	impl SignatureRasterizer for WebSignatureRasterizer {
25	    fn rasterize(
26	        &self,
27	        strokes: &[Vec<RasterPoint>],
28	        spec: &RasterSpec,
29	    ) -> Result<RasterImage, RasterError> {
30	        rasterize_impl(strokes, spec)
31	    }
32	}
33	
34	#[cfg(all(feature = "web", target_arch = "wasm32"))]
35	fn rasterize_impl(
36	    strokes: &[Vec<RasterPoint>],
37	    spec: &RasterSpec,
38	) -> Result<RasterImage, RasterError> {
39	    let window = web_sys::window().ok_or_else(|| RasterError::Backend("no window".into()))?;
40	
41	    let document = window
42	        .document()
43	        .ok_or_else(|| RasterError::Backend("no document".into()))?;
44	
45	    let canvas: HtmlCanvasElement = document
46	        .create_element("canvas")
47	        .map_err(|_| RasterError::Backend("create_element(canvas) failed".into()))?
48	        .dyn_into()
49	        .map_err(|_| RasterError::Backend("element is not a canvas".into()))?;
50	
51	    canvas.set_width(spec.width);
52	    canvas.set_height(spec.height);
53	
54	    let ctx: CanvasRenderingContext2d = canvas
55	        .get_context("2d")
56	        .map_err(|_| RasterError::Backend("get_context(2d) failed".into()))?
57	        .ok_or_else(|| RasterError::Backend("no 2d context".into()))?
58	        .dyn_into()
59	        .map_err(|_| RasterError::Backend("context is not 2d".into()))?;
60	
61	    if let Some(background) = &spec.background {
62	        ctx.set_fill_style_str(background);
63	        ctx.fill_rect(0.0, 0.0, f64::from(spec.width), f64::from(spec.height));
64	    }
65	
66	    ctx.set_stroke_style_str(&spec.pen_color);
67	    ctx.set_line_cap("round");
68	    ctx.set_line_join("round");
69	
70	    for stroke in strokes {
71	        for segment in stroke.windows(2) {
72	            let (from, to) = (segment[0], segment[1]);
73	
74	            ctx.set_line_width(spec.pen_width * pressure_scale(from.pressure, to.pressure));
75	            ctx.begin_path();
76	            ctx.move_to(from.x, from.y);
77	            ctx.line_to(to.x, to.y);
78	            ctx.stroke();
79	        }
80	    }
81	
82	    let data_url = match spec.format {
83	        RasterFormat::Png => canvas.to_data_url_with_type("image/png"),
84	
85	        RasterFormat::Jpeg => canvas.to_data_url_with_type_and_encoder_options(
86	            "image/jpeg",
87	            &JsValue::from_f64(spec.quality),
88	        ),
89	    }
90	    .map_err(|_| RasterError::Backend("toDataURL failed".into()))?;
91	
92	    let bytes = decode_data_url(&window, &data_url)?;
93	
94	    Ok(RasterImage {
95	        format: spec.format,
96	        bytes,
97	    })
98	}
99	
100	/// Maps the pressures at a segment's two endpoints to a stroke-width multiplier
101	/// in `0.5..=1.0`, so a segment is always visible (never zero width) while
102	/// firmer presses render thicker.
103	#[cfg(all(feature = "web", target_arch = "wasm32"))]
104	fn pressure_scale(from: f64, to: f64) -> f64 {
105	    let average = ((from + to) / 2.0).clamp(0.0, 1.0);
106	    0.5 + 0.5 * average
107	}
108	
109	/// Decodes a `data:<mime>;base64,<payload>` URL to raw bytes via `window.atob`.
110	///
111	/// `atob` yields a binary string whose code points are byte values `0..=255`;
112	/// truncating each `char` to `u8` recovers the original bytes.
113	#[cfg(all(feature = "web", target_arch = "wasm32"))]
114	fn decode_data_url(window: &Window, data_url: &str) -> Result<Vec<u8>, RasterError> {
115	    let base64 = data_url
116	        .split_once(',')
117	        .map(|(_, payload)| payload)
118	        .ok_or_else(|| RasterError::Backend("malformed data URL".into()))?;
119	    let binary = window
120	        .atob(base64)
121	        .map_err(|_| RasterError::Backend("atob failed".into()))?;
122	    Ok(binary.chars().map(|code| code as u8).collect())
123	}
124	
125	#[cfg(any(not(feature = "web"), not(target_arch = "wasm32")))]
126	fn rasterize_impl(
127	    _strokes: &[Vec<RasterPoint>],
128	    _spec: &RasterSpec,
129	) -> Result<RasterImage, RasterError> {
130	    Err(RasterError::Unsupported)
131	}
