8	use ars_core::{RasterError, RasterImage, RasterPoint, RasterSpec, SignatureRasterizer};
9	#[cfg(all(feature = "web", target_arch = "wasm32"))]
10	use {
11	    ars_core::RasterFormat,
12	    wasm_bindgen::{JsCast, JsValue},
13	    web_sys::{CanvasRenderingContext2d, HtmlCanvasElement, Window},
14	};
