16	/// Production [`SignatureRasterizer`] for browser builds.
17	///
18	/// Rasterizes strokes via an offscreen `<canvas>` 2D context and `toDataURL`.
19	/// On non-wasm targets (e.g. SSR type-checking) every call returns
20	/// [`RasterError::Unsupported`].
21	#[derive(Debug, Default, Clone, Copy)]
22	pub struct WebSignatureRasterizer;
23	
24	impl SignatureRasterizer for WebSignatureRasterizer {
25	    fn rasterize(
26	        &self,
27	        strokes: &[Vec<RasterPoint>],
28	        spec: &RasterSpec,
29	    ) -> Result<RasterImage, RasterError> {
30	        rasterize_impl(strokes, spec)
31	    }
32	}
33	
34	#[cfg(all(feature = "web", target_arch = "wasm32"))]
35	fn rasterize_impl(
36	    strokes: &[Vec<RasterPoint>],
37	    spec: &RasterSpec,
38	) -> Result<RasterImage, RasterError> {
39	    let window = web_sys::window().ok_or_else(|| RasterError::Backend("no window".into()))?;
40	
41	    let document = window
42	        .document()
43	        .ok_or_else(|| RasterError::Backend("no document".into()))?;
44	
45	    let canvas: HtmlCanvasElement = document
46	        .create_element("canvas")
47	        .map_err(|_| RasterError::Backend("create_element(canvas) failed".into()))?
48	        .dyn_into()
49	        .map_err(|_| RasterError::Backend("element is not a canvas".into()))?;
50	
51	    canvas.set_width(spec.width);
52	    canvas.set_height(spec.height);
53	
54	    let ctx: CanvasRenderingContext2d = canvas
55	        .get_context("2d")
56	        .map_err(|_| RasterError::Backend("get_context(2d) failed".into()))?
57	        .ok_or_else(|| RasterError::Backend("no 2d context".into()))?
58	        .dyn_into()
59	        .map_err(|_| RasterError::Backend("context is not 2d".into()))?;
60	
61	    if let Some(background) = &spec.background {
62	        ctx.set_fill_style_str(background);
63	        ctx.fill_rect(0.0, 0.0, f64::from(spec.width), f64::from(spec.height));
64	    }
65	
66	    ctx.set_stroke_style_str(&spec.pen_color);
67	    ctx.set_line_cap("round");
68	    ctx.set_line_join("round");
69	
70	    for stroke in strokes {
71	        for segment in stroke.windows(2) {
72	            let (from, to) = (segment[0], segment[1]);
73	
74	            ctx.set_line_width(spec.pen_width * pressure_scale(from.pressure, to.pressure));
75	            ctx.begin_path();
76	            ctx.move_to(from.x, from.y);
77	            ctx.line_to(to.x, to.y);
78	            ctx.stroke();
79	        }
80	    }
81	
82	    let mime = spec.format.mime();
