107	/// in `0.5..=1.0`, so a segment is always visible (never zero width) while
108	/// firmer presses render thicker.
109	#[cfg(all(feature = "web", target_arch = "wasm32"))]
110	fn pressure_scale(from: f64, to: f64) -> f64 {
111	    let average = ((from + to) / 2.0).clamp(0.0, 1.0);
112	
113	    0.5 + 0.5 * average
