120	/// substitution is reported truthfully), falling back to `requested` if the
121	/// header is unparseable. `atob` yields a binary string whose code points are
122	/// byte values `0..=255`; truncating each `char` to `u8` recovers the bytes.
123	#[cfg(all(feature = "web", target_arch = "wasm32"))]
124	fn decode_data_url(
125	    window: &Window,
126	    data_url: &str,
127	    requested: RasterFormat,
128	) -> Result<(RasterFormat, Vec<u8>), RasterError> {
129	    let (header, base64) = data_url
130	        .split_once(',')
131	        .ok_or_else(|| RasterError::Backend("malformed data URL".into()))?;
132	
133	    // header looks like `data:image/png;base64`
134	    let format = header
135	        .strip_prefix("data:")
136	        .and_then(|rest| rest.split(';').next())
137	        .and_then(RasterFormat::from_mime)
138	        .unwrap_or(requested);
