    use std::sync::Arc;

    let mut result = service.send(event);
    let send: ars_core::StrongSend<Event> = Arc::new(|_| {});
    for effect in result.pending_effects.drain(..) {
        drop(effect.run(service.context(), service.props(), Arc::clone(&send)));
    }
}

